export function historyRouter(main,Rout='') { 
   
    let history=$(location).attr('href').split(main.explode).splice(main.patroutes,5).join("/");
    if (history) {
        if (Rout=='package') {
          const myRouter = new readRouter(main);
          var segmenGet=$(location).attr('href').split("/").splice(4,12).join("/");
          return myRouter.package(main,explode(segmenGet,main.explode,0)+'/'+history);
        } else {
           var segmenGet=$(location).attr('href').split("/").splice(3,12).join("/");
           mainRouter({
             "spinner"   :main.spinner,
             "mainroute" :main.mainroute,
             "autoload"  :explode(segmenGet,main.explode,0)+'/'+history,
             "patroutes" :main.patroutes,
          })
        } 
    }

}
export function mainRouter(main,Rout='') { 

    const myRouter = new readRouter(main);
    if (Rout=='package') {
        var segmenGet=main.autoload.split("/").splice(4,5).join("/");
        return myRouter.package(main,segmenGet);  
    } else {
       return myRouter.hashtag(main);
    }
}
  


export function setRouter(main) { 
    const buttonClickHandler = event => {
       
        history.pushState({}, "", event.target.href)
        if (event.target.href !==null) {
           var segmenGet=event.target.href.split("/").splice(3,5).join("/");
       
        const myRouter = new readRouter(main);
        return myRouter.template(main,segmenGet);           
        }

    };
    $.each(main.selector,function(key1, row){
       const button = document.querySelector('#'+row);
       button.addEventListener('click', buttonClickHandler);
    });
}

export function Router(main) { 
 $('a').click(function(){
       var ulr=$(this).attr('href');
       if (ulr !=='javascript:void(0);') {
            history.replaceState('setRhref', '', ulr);
            var segmenGet=$(location).attr('href').split("/").splice(4,5).join("/");
            // console.log(segmenGet)
            const myRouter = new readRouter(main);
            return myRouter.package(main,segmenGet);  
        } 
  });
}

