export function Qrcode(main,style) { 
    // console.log(main)
    if (style) {
     var qrcode = new QRious({
       element: document.getElementById(style.selector),
       background: '#ffffff',
       backgroundAlpha: 1,
       foreground: style.color?style.color:'#5868bf',
       foregroundAlpha: 1,
       level: 'H',
       padding: 0,
       size: style.size?style.size:128,
       value: main
     });
     return qrcode;
    } else {
     return  new QRious({element: document.getElementById("qrcode"), value: main});
    }
}



export class setHttp {
    get(url) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/'+url)
                .then(res => res.json())
                .then(data => resolve(data))
                .catch(err => reject(err))

        })
    }
    select(url, data) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/select/'+url, {
                "method": 'POST',
                 "headers": {
                     "Authorization": tatiyeNet.token,
                     "Content-Type": "application/json"
                 },
                "body": JSON.stringify(data)
            })
                .then(res => res.json())
                .then(data => resolve(data))
                .catch(err => reject(err))

        })
    }
    entri(url, data) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/entri/'+url, {
                "method": 'POST',
                 "headers": {
                     "Authorization": tatiyeNet.token,
                     "Content-Type": "application/json"
                 },
                "body": JSON.stringify(data)
            })
                .then(res => res.json())
                .then(data => resolve(data))
                .catch(err => reject(err))

        })
    }

    post(url, data) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/'+url, {
                "method": 'POST',
                 "headers": {
                     "Authorization": tatiyeNet.token,
                     "Content-Type": "application/json"
                 },
                "body": JSON.stringify(data)
            })
                .then(res => res.json())
                .then(data => resolve(data))
                .catch(err => reject(err))

        })
    }
    put(url, data) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/'+url, {
                 "method": 'PUT',
                 "headers": {
                     "Authorization": tatiyeNet.token,
                     "Content-Type": "application/json"
                 },
                "body": JSON.stringify(data)
            })
                .then(res => res.json())
                .then(data => resolve(data))
                .catch(err => reject(err))

        })
    }
    delete(url, data) {
        return new Promise((resolve, reject) => {
            fetch(tatiyeNet.api+'/'+url, {
                "method": 'DELETE',
                 "headers": {
                     "Authorization": tatiyeNet.token,
                     "Content-Type": "application/json"
                 },
                "body": JSON.stringify(data)
            })
                .then(res => res.json())
                .then(() => resolve('Deleted successfully'))
                .catch(err => reject(err))

        })
    }
}


