export function setModal(style) {
        count++;
        const addModal = new Modal(
            style.titel, 
            style.width, 
            style.key, 
            style.model,
            style.route,
            style.tabel,
            style.content,
            count
            );
        // console.log(addModal)
         var resheader =style.content+style.titel.replace(/[^A-Za-z0-9]/g, '')+count;
         if(style.content == 'profil') {
            
            addModal.profil(style.titel,resheader,style.model)  
         } else if (style.content == 'delete'){
           addModal.delete(style.titel,resheader,style.model)  
         } else if (style.content == 'from'){
           addModal.from(style.titel,resheader,style.model)  
         } else if (style.content == 'upload'){
           addModal.upload(style.titel,resheader,style.model)  
         } else {
           addModal.modal(style.titel,resheader,style.model)  
         }        
}


